interface User { id: number; name: string; email: string }
interface Guest { sessionId: string }
function isUser(value: User | Guest): value is User {
  return 'id' in value && typeof (value as User).id === 'number'
}
function greet(actor: User | Guest): string {
  return isUser(actor) ? `Hello, ${actor.name}` : `Hello, guest ${actor.sessionId}`
}
